<span class="line">      <span class="token keyword">style</span> instance <span class="token style"><span class="token property">stroke</span><span class="token operator">:</span>violet<span class="token punctuation">,</span> <span class="token property">stroke-width</span><span class="token operator">:</span> 3px</span><span class="token punctuation">;</span></span>
